import{c as n,Q as s,j as a,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"解释器总览","description":"","frontmatter":{},"headers":[],"relativePath":"interpreterLearning/01-解释器总览.md","filePath":"interpreterLearning/01-解释器总览.md","lastUpdated":1778496697000}'),o={name:"interpreterLearning/01-解释器总览.md"};function r(p,t,d,l,i,c){return s(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="解释器总览" tabindex="-1">解释器总览 <a class="header-anchor" href="#解释器总览" aria-label="Permalink to &quot;解释器总览&quot;">​</a></h1><p>写一行 <code>let x = 1 + 2</code> 出来 <code>x == 3</code>,看起来一行代码的事——<strong>背后是这门语言运行时几千行代码的协作</strong>:字符串变 token、token 变 AST、AST 走求值或编译到字节码、字节码进 VM 调度循环,中间还要处理作用域、闭包、错误回滚、GC 暂停。<strong>这套机制几乎每门动态语言都长一样</strong>(就像 OS 都有进程 / 内存 / 调度),所以<strong>亲手写一遍解释器,等于一次性拆掉 JS / Python / Lua / Ruby 共用的那层抽象</strong>——之后你读 V8 / CPython 源码会快一个量级,写 DSL / 模板引擎 / 规则引擎时,<strong>第一反应是「先定义文法」,而不是堆一堆正则和 if/else 硬拼</strong>。</p><blockquote><p>一句话先记住:<strong>解释器不是黑魔法,是几千行代码的事</strong>——本系列陪你从 0 写一门叫 Mochi 的小语言,从树遍历版本一路推到字节码 VM,<strong>核心算法每个 30-80 行 TS 就能跑</strong>,30 篇打完你应该能在白板上讲清楚 V8 / CPython / Lua 的核心实现差异。</p></blockquote><hr><h2 id="一、为什么写解释器是元能力" tabindex="-1">一、为什么写解释器是元能力 <a class="header-anchor" href="#一、为什么写解释器是元能力" aria-label="Permalink to &quot;一、为什么写解释器是元能力&quot;">​</a></h2><p>应用工程师 99% 的时间在「用语言」,而不是「看语言怎么实现」。结果是:</p><ul><li>看到「闭包捕获 by reference」只会背规则,不知道<strong>实现层为什么必须 by reference</strong>(否则递归引用环建不起来,closure 之间互相调用就崩)</li><li>写 React <code>useCallback</code> 反复抓 bug,<strong>因为不知道 V8 把 closure 编译成了什么样、什么时候会 deopt</strong></li><li>写配置 DSL,<strong>第一反应是写正则</strong>,正则没法处理嵌套就硬塞 <code>eval</code>,留下注入风险</li><li>看 CPython 源码,看到 <code>Python/ceval.c</code> 那一万行 switch 直接关掉——<strong>因为不知道那就是字节码 VM 的调度循环</strong></li></ul><p><strong>解释器是 OS 之外、应用工程师最值得拆的一层抽象</strong>——和 OS 不同的是,<strong>几千行代码就能写完一个能用的玩具版</strong>(Lox 3000 行,Monkey 2500 行,Mochi 目标 3500 行)。拆完之后,几个看似神秘的东西会瞬间塌缩:</p><table tabindex="0"><thead><tr><th>之前的感觉</th><th>拆完之后</th></tr></thead><tbody><tr><td>闭包是&quot;魔法&quot;</td><td>闭包就是一个函数对象 + 一个环境指针</td></tr><tr><td>GC 是&quot;黑盒&quot;</td><td>mark-sweep 三色标记 50 行能写出来</td></tr><tr><td>AST 是&quot;理论东西&quot;</td><td>AST 就是一个 sum type / discriminated union</td></tr><tr><td>字节码是&quot;汇编近亲&quot;</td><td>字节码就是一个 <code>Uint8Array</code>,VM 是一个 <code>while + switch</code></td></tr><tr><td>异常是&quot;语言特性&quot;</td><td>异常就是带 try 栈的非局部跳转</td></tr></tbody></table><hr><h2 id="二、三种姿态-解释器-编译器-jit" tabindex="-1">二、三种姿态:解释器 / 编译器 / JIT <a class="header-anchor" href="#二、三种姿态-解释器-编译器-jit" aria-label="Permalink to &quot;二、三种姿态:解释器 / 编译器 / JIT&quot;">​</a></h2><p>「语言怎么跑」其实有三种基础姿态——一门真实语言往往是几种的组合。</p><table tabindex="0"><thead><tr><th>维度</th><th>解释器(Interpreter)</th><th>编译器(Compiler)</th><th>JIT</th></tr></thead><tbody><tr><td>何时翻译</td><td>边读边执行</td><td>一次性翻成机器码</td><td>跑起来后边跑边翻</td></tr><tr><td>输出物</td><td>无(直接执行)</td><td>可执行文件</td><td>内存里的机器码 page</td></tr><tr><td>启动</td><td>快</td><td>慢(要先编译)</td><td>快(冷代码走解释器)</td></tr><tr><td>峰值性能</td><td>慢</td><td>快</td><td>接近编译器(热代码)</td></tr><tr><td>调试体验</td><td>好(可中断、可 REPL)</td><td>一般</td><td>痛苦(代码动态生成、栈帧奇怪)</td></tr><tr><td>典型代表</td><td>早期 Python / Bash / tree-walk Lox</td><td>C / Rust / Go(AOT)</td><td>V8 / HotSpot / LuaJIT / PyPy</td></tr></tbody></table><p>但<strong>现实里很少是&quot;纯解释器&quot;</strong>——CPython 不是 tree walk,它先把 <code>.py</code> 编译成 <code>.pyc</code>(字节码),再用解释器跑字节码;V8 干脆是「字节码解释器 Ignition + JIT TurboFan + Maglev + Sparkplug」四个执行引擎接力。<strong>所以更准确的分法是「翻译停在哪一层」</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源码</span></span>
<span class="line"><span> ├─ 一路走到底 → 机器码           (C / Rust / Go AOT)</span></span>
<span class="line"><span> ├─ 中间停在 AST → 直接求值        (tree-walk 解释器,本系列 01-19)</span></span>
<span class="line"><span> ├─ 中间停在字节码 → VM 执行字节码  (CPython / Lua / JVM,本系列 20-25)</span></span>
<span class="line"><span> └─ 字节码热路径 → 翻成机器码      (V8 / HotSpot / PyPy JIT)</span></span></code></pre></div><p>「编译」和「解释」是连续光谱,<strong>不是非黑即白——停在哪一层,就是性能 vs 复杂度的取舍</strong>。</p><hr><h2 id="三、不是黑魔法-数代码量" tabindex="-1">三、不是黑魔法:数代码量 <a class="header-anchor" href="#三、不是黑魔法-数代码量" aria-label="Permalink to &quot;三、不是黑魔法:数代码量&quot;">​</a></h2><p>很多人觉得「写解释器 = 啃龙书 = 半年起步」,这是被大学编译原理课劝退的副作用。<strong>真实的玩具/嵌入式解释器数据</strong>:</p><table tabindex="0"><thead><tr><th>项目</th><th>类型</th><th>代码量</th><th>宿主语言</th><th>状态</th></tr></thead><tbody><tr><td>Lox / jlox(《Crafting Interpreters》)</td><td>tree-walk</td><td>~2200 行</td><td>Java</td><td>教科书</td></tr><tr><td>Lox / clox(《Crafting Interpreters》)</td><td>字节码 VM</td><td>~3500 行</td><td>C</td><td>教科书</td></tr><tr><td>Monkey(《Writing An Interpreter in Go》)</td><td>tree-walk</td><td>~2500 行</td><td>Go</td><td>教科书</td></tr><tr><td>Wren</td><td>字节码 VM</td><td>~9000 行</td><td>C</td><td>嵌入式可用</td></tr><tr><td>Lua 5.4 内核</td><td>字节码 VM</td><td>~25000 行</td><td>C</td><td><strong>生产语言</strong></td></tr><tr><td><strong>本系列 Mochi 目标</strong></td><td>tree-walk → 字节码</td><td><strong>~3500 行</strong></td><td>TypeScript</td><td>玩具</td></tr></tbody></table><p>Lua 是反例里最猛的——<strong>一门嵌进无数游戏引擎、Redis、Nginx、OpenResty 的生产可用语言,核心代码 25k 行 C</strong>。魔兽世界、Roblox 都跑在它上面。</p><p><strong>结论</strong>:不要被「编译原理」四个字吓到。<strong>解释器这一层是「少量代码 + 大量精妙抽象」——这恰好是它适合作为元能力训练的原因</strong>:动手成本低,认知收益超高。</p><hr><h2 id="四、心智图-源码到结果的五个站点" tabindex="-1">四、心智图:源码到结果的五个站点 <a class="header-anchor" href="#四、心智图-源码到结果的五个站点" aria-label="Permalink to &quot;四、心智图:源码到结果的五个站点&quot;">​</a></h2><p>不管什么语言,从你按下回车到屏幕上出现结果,中间这条路上<strong>最多 5 个站点</strong>——记住下面这张图,30 篇都在填它的细节:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                ┌─────────────┐</span></span>
<span class="line"><span>源码字符流 ────→ │   Lexer     │ ── tokens ──→</span></span>
<span class="line"><span>&quot;1 + 2&quot;          │  词法分析   │  [NUM 1] [PLUS] [NUM 2]</span></span>
<span class="line"><span>                 └─────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                 ┌─────────────┐</span></span>
<span class="line"><span>   tokens   ───→ │   Parser    │ ── AST ──→</span></span>
<span class="line"><span>                 │  语法分析   │   BinaryExpr(+)</span></span>
<span class="line"><span>                 └─────────────┘    ├─ NumLit(1)</span></span>
<span class="line"><span>                                    └─ NumLit(2)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         ┌─── 路线 A:树遍历 ──┐   ┌─── 路线 B:字节码 ───┐</span></span>
<span class="line"><span>         │                     │   │                      │</span></span>
<span class="line"><span>         ↓                     │   ↓                      │</span></span>
<span class="line"><span>   ┌────────────┐              │  ┌────────────┐          │</span></span>
<span class="line"><span>   │ Evaluator  │              │  │  Compiler  │          │</span></span>
<span class="line"><span>   │  走 AST    │              │  │ AST→bytecode│         │</span></span>
<span class="line"><span>   └────────────┘              │  └────────────┘          │</span></span>
<span class="line"><span>         │                     │        │                  │</span></span>
<span class="line"><span>         ↓                     │        ↓                  │</span></span>
<span class="line"><span>       结果 3                  │   [CONST 1] [CONST 2]     │</span></span>
<span class="line"><span>                               │   [ADD]     [RETURN]      │</span></span>
<span class="line"><span>                               │        │                  │</span></span>
<span class="line"><span>                               │        ↓                  │</span></span>
<span class="line"><span>                               │   ┌────────────┐          │</span></span>
<span class="line"><span>                               │   │     VM     │          │</span></span>
<span class="line"><span>                               │   │ 调度循环   │          │</span></span>
<span class="line"><span>                               │   └────────────┘          │</span></span>
<span class="line"><span>                               │        │                  │</span></span>
<span class="line"><span>                               │        ↓                  │</span></span>
<span class="line"><span>                               │     结果 3                │</span></span>
<span class="line"><span>                               └───────────────────────────┘</span></span></code></pre></div><p><strong>两条路线的取舍</strong>:</p><ul><li>路线 A(树遍历):简单,几百行能写完;<strong>慢</strong>——每次执行都要重新遍历树并做类型派发,cache 不友好</li><li>路线 B(字节码):多一个编译步骤,但运行时只剩一个紧凑的 <code>while + switch</code>;<strong>实测比 A 快 5-10 倍</strong></li></ul><p>本系列 01-19 篇走 A,把 Mochi 写出来能跑;20-25 篇切换到 B,<strong>让同一份测试用例跑得快好几倍</strong>——加速比实测出来本身就是这层最爽的反馈。</p><hr><h2 id="五、本系列要产出什么" tabindex="-1">五、本系列要产出什么 <a class="header-anchor" href="#五、本系列要产出什么" aria-label="Permalink to &quot;五、本系列要产出什么&quot;">​</a></h2><p>不是 30 篇空文,三件实物:</p><ol><li><strong>Mochi 语言本身</strong>——动态类型、一等公民函数、闭包、类、模块、try/catch,能跑一段含这些特性的脚本</li><li><strong>GitHub 仓库 <code>mochi-lang</code></strong>——按篇分 tag,每篇对应一个可运行版本,<strong><code>pnpm test</code> 全过才能打勾</strong></li><li><strong>「从 Mochi 到真实源码」的索引</strong>——CPython 的 <code>ceval.c</code> 在哪一行做调度循环、V8 的 Ignition 在哪个目录、Lua 的 <code>lvm.c</code> 怎么实现 <code>OP_ADD</code>,<strong>你的下一站直接落地</strong></li></ol><p>宿主语言锁定 <strong>TypeScript</strong>(读者基数广)+ <strong>Rust</strong>(关键算法贴近工业级)。<strong>不用 Python 写解释器</strong>——后面 VM 篇章要测「树遍历 vs 字节码」的实际加速比,<strong>宿主太慢会让结论失去说服力</strong>。</p><hr><h2 id="六、立场" tabindex="-1">六、立场 <a class="header-anchor" href="#六、立场" aria-label="Permalink to &quot;六、立场&quot;">​</a></h2><ul><li><strong>不啃龙书</strong>——不证明文法等价性,工程师视角够用就行</li><li><strong>不抄《Crafting Interpreters》</strong>——那本书在那儿,本系列补它没讲透的「为什么」和「工业级是怎么做的」</li><li><strong>Mochi 是玩具</strong>——所有&quot;为了简单而省略&quot;的地方都明确标注「Mochi 这里偷懒了 / 真实语言会怎么做」,确保你知道边界在哪</li><li><strong>每篇独立可读,但 Mochi 仓库一路叠加</strong>——不是孤立的 demo,是一门越长越大的真实语言</li></ul><hr><p>下一篇:<code>02-一段代码怎么跑起来.md</code>,把 <code>print(1 + 2)</code> 这一行 Mochi 代码<strong>从字符串变成屏幕上的 <code>3</code></strong>,每一步贴一个数据结构 snapshot——让你<strong>看清楚字符流、tokens、AST、字节码</strong> 这四种物理形态各是什么,以及为什么 CPython / V8 走的也是同一条路。</p>`,39)])])}const u=n(o,[["render",r]]);export{g as __pageData,u as default};
